import React, { useState, useEffect } from "react";
import { Link, useNavigate } from "react-router-dom";
import { motion } from "framer-motion";
import { propertyService } from "../services/api";
import PropertyCard from "../components/PropertyCard";
import "../styles/Home.css";

const Home = () => {
    const [featuredProperties, setFeaturedProperties] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchParams, setSearchParams] = useState({
        propertyType: "",
        city: "",
        minPrice: "",
        maxPrice: ""
    });

    const navigate = useNavigate();

    useEffect(() => {
        fetchFeaturedProperties();
    }, []);

    const fetchFeaturedProperties = async () => {
        try {
            const response = await propertyService.getAllProperties({ limit: 6 });
            setFeaturedProperties(response.data.data);
        } catch (err) {
            console.error("Failed to fetch featured properties", err);
        } finally {
            setLoading(false);
        }
    };

    const handleSearchChange = (e) => {
        setSearchParams({
            ...searchParams,
            [e.target.name]: e.target.value
        });
    };

    const handleSearchSubmit = (e) => {
        e.preventDefault();
        const queryParams = new URLSearchParams(searchParams).toString();
        navigate(`/properties?${queryParams}`);
    };

    const containerVariants = {
        hidden: { opacity: 0 },
        visible: {
            opacity: 1,
            transition: {
                staggerChildren: 0.2,
                delayChildren: 0.2,
            },
        },
    };

    const itemVariants = {
        hidden: { opacity: 0, y: 20 },
        visible: {
            opacity: 1,
            y: 0,
            transition: { duration: 0.8, ease: "easeOut" },
        },
    };

    return (
        <div className="home-container">
            <motion.section 
                className="hero-section"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ duration: 1 }}
            >
                <motion.div 
                    className="hero-content"
                    variants={containerVariants}
                    initial="hidden"
                    animate="visible"
                >
                    <motion.h1
                        variants={itemVariants}
                        className="hero-title"
                    >
                        Find Your Dream Home
                    </motion.h1>
                    <motion.p
                        variants={itemVariants}
                        className="hero-subtitle"
                    >
                        Search over 10,000 properties across India
                    </motion.p>

                    <motion.form 
                        className="hero-search"
                        onSubmit={handleSearchSubmit}
                        variants={itemVariants}
                    >
                        <motion.select 
                            name="propertyType" 
                            value={searchParams.propertyType} 
                            onChange={handleSearchChange}
                            whileFocus={{ scale: 1.02 }}
                        >
                            <option value="">Property Type</option>
                            <option value="House">House</option>
                            <option value="Apartment">Apartment</option>
                            <option value="Villa">Villa</option>
                            <option value="Plot">Plot</option>
                        </motion.select>
                        <motion.input
                            type="text"
                            name="city"
                            placeholder="Location"
                            value={searchParams.city}
                            onChange={handleSearchChange}
                            whileFocus={{ scale: 1.02 }}
                        />
                        <motion.button 
                            type="submit"
                            whileHover={{ scale: 1.05 }}
                            whileTap={{ scale: 0.95 }}
                        >
                            Search
                        </motion.button>
                    </motion.form>
                </motion.div>
            </motion.section>

            <section className="featured-section">
                <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    transition={{ duration: 0.6 }}
                    viewport={{ once: true }}
                >
                    <h2>Featured Properties</h2>
                    <p className="section-subtitle">Discover our handpicked selection of premium properties</p>
                </motion.div>

                {loading ? (
                    <motion.div 
                        className="loading"
                        animate={{ rotate: 360 }}
                        transition={{ duration: 2, repeat: Infinity }}
                        style={{ textAlign: 'center', padding: '40px' }}
                    >
                        Loading...
                    </motion.div>
                ) : (
                    <motion.div 
                        className="properties-grid"
                        variants={containerVariants}
                        initial="hidden"
                        animate="visible"
                    >
                        {featuredProperties.map((property, index) => (
                            <motion.div
                                key={property._id}
                                variants={itemVariants}
                                whileHover={{ y: -10 }}
                            >
                                <PropertyCard property={property} />
                            </motion.div>
                        ))}
                    </motion.div>
                )}

                <motion.div
                    className="view-all-container"
                    initial={{ opacity: 0 }}
                    whileInView={{ opacity: 1 }}
                    transition={{ duration: 0.6 }}
                    viewport={{ once: true }}
                >
                    <Link to="/properties" className="view-all-btn">
                        View All Properties
                    </Link>
                </motion.div>
            </section>

            <motion.section
                className="features-section"
                initial={{ opacity: 0 }}
                whileInView={{ opacity: 1 }}
                transition={{ duration: 0.8 }}
                viewport={{ once: true }}
            >
                <h2>Why Choose Us</h2>
                <motion.div 
                    className="features-grid"
                    variants={containerVariants}
                    initial="hidden"
                    whileInView="visible"
                    viewport={{ once: true }}
                >
                    <motion.div className="feature-card" variants={itemVariants}>
                        <div className="feature-icon">🏠</div>
                        <h3>Verified Properties</h3>
                        <p>All properties are thoroughly verified by our expert team</p>
                    </motion.div>
                    <motion.div className="feature-card" variants={itemVariants}>
                        <div className="feature-icon">🔒</div>
                        <h3>Secure Transactions</h3>
                        <p>Your transactions are protected by our secure platform</p>
                    </motion.div>
                    <motion.div className="feature-card" variants={itemVariants}>
                        <div className="feature-icon">📞</div>
                        <h3>24/7 Support</h3>
                        <p>Our customer support team is always ready to help</p>
                    </motion.div>
                    <motion.div className="feature-card" variants={itemVariants}>
                        <div className="feature-icon">⚡</div>
                        <h3>Fast Process</h3>
                        <p>Complete your property search in minutes, not days</p>
                    </motion.div>
                </motion.div>
            </motion.section>
        </div>
    );
};

export default Home;
